<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit">
            <template v-slot:tgslot-Location="{ data }">
                    <div class="input-group">
                        <input type="text" v-model="LocationValue" :class="{'form-control w-100':true,'is-invalid':data.error.length !=''}" :name="Location" @keyup="searchFunction">
                    </div>
            </template>
            <template v-slot:tgslot-Subject="{ data }">
                  <div class="input-group">
                        <input type="text" v-model="SubjectValue" :class="{'form-control w-100':true,'is-invalid':data.error.length !=''}" :name="Subject" @keyup="searchFunction">
                    </div>
            </template>
            <template v-slot:tgslot-TicketNumber="{ data }">
                  <div class="input-group">
                        <input type="text" v-model="ticketNumberval" :class="{'form-control w-100':true,'is-invalid':data.error.length !=''}" :name="TicketNumber" @keyup="searchFunction">
                    </div>
            </template>
        </dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
    </template>
    
    <script>
    import DataServices from "../../services/DataService";
    import ReportViewer from '../HrReport/ReportViewer.vue';
   

    export default {
        components: {
            ReportViewer
        },
        data() {
                return {
                LocationValue:"",
                SubjectValue:"",
                ticketNumberval:"",
                searchCondition:"",
                isLoading: false,
                 reportPath: null,
                 parameter: [],
                // FindalLocationArray: [],          
                FormSchema: [{
                        layoutType: "triple",
                        Data: [
                            {
                                astype: "SlotField",
                                label: this.$t('Location'),
                                name: "Location",
                                value: "",
                                placeholder: "Search by Location",
                            },                            
                            {
                                astype: "SlotField",
                                label: this.$t('Subject'),
                                name: "Subject",
                                value: "",
                                placeholder: "Search by Subject",
                            },  
                           {
                                astype: "TextField",
                                label: this.$t("Ticket Text"),
                                name: "TicketText",
                                value: "",
                                placeholder: "Search by Ticket Text",
                                validationRules: { "required": false, max: 250 },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Ticket Type"),
                                name: "TicketType",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Ticket Type'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    onChange: this.searchFunction
                                },
                            },
                            {
                                astype: "SlotField",
                                label: this.$t("Ticket Number"),
                                name: "TicketNumber",
                                value: "",
                                placeholder: "Search by Ticket Number",
                                validationRules: { "required": false, max: 250 },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Assigned"),
                                name: "Assigned",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Users'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    onChange: this.searchFunction
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Status"),
                                name: "Status",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Status'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    onChange: this.searchFunction
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Supervisor"),
                                name: "Supervisor",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Supervisor'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Critical Approval"),
                                name: "CriticalApproval",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Approval Status'),
                                mode: "tag",
                                config: {
                                    options: [{name:'Approval Pending', value:'APPROVE_PENDING'}, {name:'Approved', value:'APPROVED'}]
                                  
                                },
                            },
                        ],
                    },
                    {
                        layoutType: "four",
                        Data: [
                        {
                                astype: "SelectField",
                                label: this.$t("Form Submit"),
                                name: "FormSubmit",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('FormSubmit'),
                                mode: "tag",
                                config: {
                                    options: [{name:'Yes', value:1},{name:'No', value:0}],
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Tags"),
                                name: "Tags",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Tags'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                            {
                              astype: "DateField",
                              label: this.$t("Ticket Created Date (M/D/YYYY)" ),
                              name: "dateFrom",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
                              config: {
                                  format: "M/D/YYYY"
                              },
                            },
                          {
                              astype: "DateField",
                              label: '',
                              name: "dateTo",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
                              config: {
                                  format: "M/D/YYYY"
                              },
                          },
                        ],
                    },
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            debugger
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.DataLoaded = 1;
           await vm.BindTicketType();
           await vm.BindUsers();
           await vm.GetStatusList();
           await vm.BindSupervisor();
           await vm.BindTags();
        },
        methods: {
    
            // ClearAll: function () {
            //     debugger;
            //     var vm = this;
            //     (vm.FormSchema)[0].Data[0].value = '';
            //     (vm.FormSchema)[0].Data[1].value = '';
            //     (vm.FormSchema)[0].Data[2].value = '';
            //     (vm.FormSchema)[0].Data[3].value = '';
            //     (vm.FormSchema)[1].Data[0].value = '';
            //     (vm.FormSchema)[1].Data[1].value = '';
            //     (vm.FormSchema)[1].Data[2].value = '';
            //     // vm.parameter = [];
            // },
           
        ClearAll: function () {
            debugger;
            var vm = this;
            
            // Reset the values to empty strings for all form fields
            vm.LocationValue = '';
            vm.SubjectValue = '';
            vm.ticketNumberval = '';
            vm.searchCondition = '';

            // Reset the values in the FormSchema directly to ensure reactivity
            vm.FormSchema.forEach((layout) => {
                layout.Data.forEach((field) => {
                    if (field.value !== undefined) {
                        field.value = '';
                    }
                });
            });
            
            // Optionally, reset the parameter if needed
            vm.parameter = [];

            // Make sure you call the method to trigger updates, if needed.
            vm.$refs.BarcodeReport.UpdateKeyValue(); // Ensure the form is updated with cleared values.
        },

            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                var vm = this;
                vm.isLoading=true;
                vm.reportPath = '';      
                vm.parameter=[];
                let myObj = {
                    reportName: "fieldserviceticketreport",
                    SupervisorIds: e.Supervisor,
                    Tags: e.Tags,
                    isFormSubmitted: e.FormSubmit,
                    TicketText:e.TicketText,
                    WorkOrderApprovalPending: e.CriticalApproval,
                    searchCondition: vm.searchCondition
                }
                var postString = JSON.stringify(myObj);   
                 DataServices.ReportMain(postString).then(function (response) {
                    debugger;
                    vm.reportPath = response.data.ReportPath;
                    vm.parameter = response.data.parameters;
                })
                vm.isLoading=false;
            },
            onLocationKeyup(event) {
                debugger;
            },

searchFunction() {
    debugger;
    this.searchCondition = "";
    this.IsApprovalSearch = false;
    this.IsFormSubmittedSearch = false;
    this.TicketType = this.FormSchema[0].Data[3].value;
    this.AssignedTo = this.FormSchema[0].Data[5].value;
    this.Status = this.FormSchema[0].Data[6].value;
    // Building search condition for Location value
    if (this.LocationValue !== "") {
      this.searchCondition += this.searchCondition ? " AND" : "";
      this.searchCondition += ` (ISNULL(TPIN.COUNTY,'') LIKE '%${this.LocationValue}%' OR `;
      this.searchCondition += `ISNULL(TPIN.PLACE,'') LIKE '%${this.LocationValue}%' OR `;
      this.searchCondition += `ISNULL(TPIN.ADDRNAME,'') LIKE '%${this.LocationValue}%' OR `;
      this.searchCondition += `ISNULL(TPIN.ADDRFROM,'') LIKE '%${this.LocationValue}%' OR `;
      this.searchCondition += `ISNULL(TPIN.DIGSTREET,'') LIKE '%${this.LocationValue}%' OR `;
      this.searchCondition += `ISNULL(TPIN.STATE,'') LIKE '%${this.LocationValue}%' )`;
    }

    // Ticket Type Search Condition
    if (this.TicketType !== "") {
      this.searchCondition += this.searchCondition ? " AND" : "";
      this.searchCondition += ` TPIN.TYPE_ID = ${this.TicketType}`;
    }

    // Approval and Form Submission Search Flags
    if (this.WorkOrderApprovalPending  !== "") {
      this.IsApprovalSearch = true;
    }
    if (this.IsFormSubmitted !== "") {
      this.IsFormSubmittedSearch = true;
    }

    // Subject Search Condition
    if (this.SubjectValue  !== "") {
      this.searchCondition += this.searchCondition ? " AND" : "";
      this.searchCondition += ` TPIN.TYPEOFWORK LIKE '${this.SubjectValue}'`;
    }

    // Ticket Number Search Condition 
    if (this.ticketNumberval  !== "") {
      this.searchCondition += this.searchCondition ? " AND" : "";
      this.searchCondition += ` TPIN.TICKETNUMBER LIKE '${this.ticketNumberval}'`;
    }

    // Assigned To Search Condition
    if (this.AssignedTo  !== "") {
      this.searchCondition += this.searchCondition ? " AND" : "";
      if (this.AssignedTo === '-1') {
        this.searchCondition += " isnull(TICK.Assigned_To,0) = 0 ";
      } else {
        this.searchCondition += ` TICK.Assigned_To = ${this.AssignedTo}`;
      }
    }

    // Status Search Condition
    if (this.Status  !== "") {
      this.searchCondition += this.searchCondition ? " AND" : "";
      this.searchCondition += ` TICK.status_id = ${this.Status}`;
    }

    // // Pagination setup
    // this.CurrentPage = 1;
    // this.PageSize = 10;
    // this.PageNumber = 1;

    // // Fetch records
    // this.fetchRecords();

    // Set search condition in input field
    //document.getElementById('searchCondition').value = this.searchCondition;
  },
            BindTicketType: async function () {
            var vm = this;
            var url = `id=&moduleName=FSM&type=FSM_TICKET_TYPE&search=&refId`;
            await DataServices.GetDDLData(url).then((response) => {
                if (response.data.DATA.length > 0) {
                    var DepartmentData = response.data.DATA;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.name,
                            value: element.value
                            
                        }
                        vm.FormSchema[0].Data[3].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },

        BindUsers: async function () {
            var vm = this;
            var url = `id=&moduleName=FSM&type=FSM_USERS&search=&refId`;
            await DataServices.GetDDLData(url).then((response) => {
                if (response.data.length > 0) {
                    var DepartmentData = response.data;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.name,
                            value: element.value
                        }
                        vm.FormSchema[0].Data[5].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
           
        GetStatusList: async function () {
                var vm = this;
                var url = `langCode=en&statusType=Ticketing&hasglobal=false`
                await DataServices.GetStatusList(url).then((response) => {
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.STATUS,
                                value: element.STATUS_ID
                            }
                            vm.FormSchema[0].Data[6].config.options.push(Obj);
                        });
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

            BindSupervisor: async function () {
            var vm = this;
            var url = `id=&moduleName=FSM&type=TICKET_SUPERVISOR&search=&refId`;
            await DataServices.GetDDLData(url).then((response) => {
                if (response.data.length > 0) {
                    var DepartmentData = response.data;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.name,
                            value: element.value
                        }
                        vm.FormSchema[0].Data[7].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        BindTags: async function () {
            var vm = this;
            var url = `id=&moduleName=FSM&type=TAG_DATA&search=&refId`;
            await DataServices.GetDDLData(url).then((response) => {
                if (response.data.length > 0) {
                    var DepartmentData = response.data;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.name,
                            value: element.value
                        }
                        vm.FormSchema[1].Data[1].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },

        }
    };
    </script>
    