<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
    </template>
    
    <script>
    import DataServices from "../../services/DataService";
    import ReportViewer from '../HrReport/ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                isLoading: false,
                 reportPath: null,
                 parameter: [],
                // FindalLocationArray: [],          
                FormSchema: [    
                    {
                        layoutType: "four",
                        Data: [
                            {
                                astype: "SelectField",
                                label: this.$t("Work order Status"),
                                name: "WorkorderStatus",
                                value: "",
                                placeholder: this.$t('Select'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Ticket Status"),
                                name: "TicketStatus",
                                value: "",
                                placeholder: this.$t('Select'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                            {
                              astype: "DateField",
                              label: this.$t("Ticket Created Date (M/D/YYYY)"),
                              name: "Fromdate",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
  
                              config: {
                                  format: "M/D/YYYY"
                              },
                            },
                          {
                              astype: "DateField",
                              label: '',
                              name: "ToDate",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
  
                              config: {
                                  format: "M/D/YYYY"
                              },
                          },

                          {
                              astype: "DateField",
                              label: this.$t("Ticket Closed Date (M/D/YYYY)"),
                              name: "dtFrom",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
  
                              config: {
                                  format: "M/D/YYYY"
                              },
                            },
                          {
                              astype: "DateField",
                              label: '',
                              name: "dtTO",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
  
                              config: {
                                  format: "M/D/YYYY"
                              },
                          },
                            
                        ],
                    },
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            debugger
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.DataLoaded = 1;   
            await vm.BindWorkorderStatus();
            await vm.GetStatusList();
        },
        methods: {
    
            ClearAll: function () {
                var vm = this;
                (vm.FormSchema)[0].Data[0].value = '';
                (vm.FormSchema)[0].Data[1].value = '';
                (vm.FormSchema)[0].Data[2].value = '';
                (vm.FormSchema)[0].Data[3].value = '';
                // vm.parameter = [];
            },
    
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                var vm = this;
                vm.isLoading=true;
                vm.reportPath = '';      
                vm.parameter=[];
                let myObj = {
                    reportName: "workorderactiveticketclosedreport",
                    dateFrom: (e.Fromdate === '') ? '' : e.Fromdate,
                    dateTo:  (e.ToDate === '') ? '' : e.ToDate,
                    ticketClosedDateFrom: (e.dtFrom === '') ? '' : e.dtFrom,
                    ticketClosedDateTo:  (e.dtTO === '') ? '' : e.dtTO,
                    StatusIds: e.WorkorderStatus,
                    ticketingStatusIds: e.TicketStatus
                    
                }
                var postString = JSON.stringify(myObj);   
                 DataServices.ReportMain(postString).then(function (response) {
                    debugger;
                    vm.reportPath = response.data.reportpath;
                    vm.parameter = response.data.parameters;
                })
                vm.isLoading=false;
            },

            BindWorkorderStatus: async function () {
            var vm = this;
            await DataServices.GetWorkOrderStatusActiveCompleteReport().then((response) => {
                debugger;
                if (response.data.length > 0) {
                    var DepartmentData = response.data;
                    DepartmentData.forEach(element => {
                        var Obj = {
                            name: element.STATUS_NAME,
                            value: element.STATUS_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });  
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetStatusList: async function () {
                    var vm = this;
                    var url = `langCode=en&statusType=Ticketing&hasglobal=false`
                    await DataServices.GetStatusList(url).then((response) => {
                        if (response.data.length > 0) {
                            var LocationData = response.data;
                            LocationData.forEach(element => {
                                var Obj = {
                                    name: element.STATUS,
                                    value: element.STATUS_ID
                                }
                                vm.FormSchema[0].Data[1].config.options.push(Obj);
                            });
                            vm.$refs.BarcodeReport.UpdateKeyValue();
                        }
                    });
                },
            }
        };
    </script>
    